// netlify/functions/submit.js
// Цей файл запускається на сервері — токен недоступний у браузері
 
exports.handler = async (event) => {
  if (event.httpMethod !== 'POST') {
    return { statusCode: 405, body: 'Method Not Allowed' };
  }
 
  // Rate limiting через заголовки (Netlify Edge)
  const ip = event.headers['x-forwarded-for'] || 'unknown';
 
  let data;
  try {
    data = JSON.parse(event.body);
  } catch {
    return { statusCode: 400, body: 'Invalid JSON' };
  }
 
  // Honeypot check
  if (data._honey) {
    return { statusCode: 200, body: 'OK' }; // bot — тихо ігноруємо
  }
 
  // Валідація
  if (!data.name || !data.contact) {
    return { statusCode: 400, body: 'Missing required fields' };
  }
 
  // Sanitize — прибираємо HTML теги
  const clean = (str) => String(str || '').replace(/<[^>]*>/g, '').trim().slice(0, 500);
 
  const name    = clean(data.name);
  const contact = clean(data.contact);
  const email   = clean(data.email);
  const biz     = clean(data.biz);
  const msg     = clean(data.msg);
  const lang    = clean(data.lang);
 
  // Telegram — токен береться з env змінної (не з коду!)
  const text = `🔔 *New Lead — Voltex Agency*\n\n👤 *Name:* ${name}\n📞 *Contact:* ${contact}\n📧 *Email:* ${email || '—'}\n🏢 *Business:* ${biz || '—'}\n💬 *Message:* ${msg || '—'}\n🌐 *Lang:* ${lang.toUpperCase()}`;
 
  try {
    await fetch(`https://api.telegram.org/bot${process.env.TG_TOKEN}/sendMessage`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        chat_id: process.env.TG_CHAT_ID,
        text,
        parse_mode: 'Markdown'
      })
    });
  } catch (e) {
    console.error('Telegram error:', e);
  }
 
  // Formspree
  try {
    await fetch('https://formspree.io/f/mdayjqey', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Accept': 'application/json' },
      body: JSON.stringify({ name, contact, email, business: biz, message: msg, lang })
    });
  } catch (e) {
    console.error('Formspree error:', e);
  }
 
  return {
    statusCode: 200,
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ ok: true })
  };
};
 
